# feature_flags.py — model routing via feature flags for canary rollout
import hashlib

# Canary configuration (loaded from feature flag service in production)
CANARY_CONFIG = {
    "new_model_v2": {
        "enabled": True,
        "percentage": 5,              # Serve 5% of traffic to canary
        "model_id": "claude-opus-4-5",
        "prompt_version": "v5.1",
    }
}

STABLE_CONFIG = {
    "model_id": "claude-3-5-sonnet-20241022",
    "prompt_version": "v4.2",
    "variant": "stable",
}

def get_model_for_request(user_id: str, feature: str = "new_model_v2") -> dict:
    """
    Deterministically assign a user to canary or stable based on user_id hash.
    The hash ensures the same user always sees the same variant (session stickiness).
    Returns a model config dict.
    """
    config = CANARY_CONFIG.get(feature)
    if not config or not config["enabled"]:
        return STABLE_CONFIG

    # Stable hash: user always gets the same bucket
    hash_val = int(hashlib.sha256(
        f"{user_id}:{feature}".encode()
    ).hexdigest(), 16) % 100

    if hash_val < config["percentage"]:
        return {
            "model_id": config["model_id"],
            "prompt_version": config["prompt_version"],
            "variant": "canary",
        }
    return STABLE_CONFIG


