#!/usr/bin/env python3
# canary_health_check.py — evaluate whether canary is healthy enough to progress

import requests, sys
from datetime import datetime, timedelta, timezone

METRICS_API = "http://metrics-service/api/v1"

def fetch_metrics(variant: str, window_minutes: int = 60) -> dict:
    since = (datetime.now(timezone.utc) - timedelta(minutes=window_minutes)).isoformat()
    resp = requests.get(f"{METRICS_API}/summary", params={"variant": variant, "since": since})
    resp.raise_for_status()
    return resp.json()

def evaluate_health(canary: dict, stable: dict) -> tuple[bool, list[str]]:
    """Returns (is_healthy, list_of_failures)."""
    failures = []

    err_delta = canary["error_rate"] - stable["error_rate"]
    if err_delta > 0.01:
        failures.append(f"Error rate delta +{err_delta*100:.2f}pp exceeds 1pp threshold")

    latency_pct = (canary["p99_latency_ms"] - stable["p99_latency_ms"]) / stable["p99_latency_ms"]
    if latency_pct > 0.15:
        failures.append(f"p99 latency regression +{latency_pct*100:.1f}% exceeds 15% threshold")

    quality_delta = canary.get("quality_score", 4.0) - stable.get("quality_score", 4.0)
    if quality_delta < -0.1:
        failures.append(f"Quality score delta {quality_delta:.2f} below -0.1 threshold")

    cost_pct = (canary["cost_per_request"] - stable["cost_per_request"]) / stable["cost_per_request"]
    if cost_pct > 0.25:
        failures.append(f"Cost delta +{cost_pct*100:.1f}% exceeds 25% threshold")

    return len(failures) == 0, failures

if __name__ == "__main__":
    canary = fetch_metrics("canary")
    stable = fetch_metrics("stable")
    healthy, failures = evaluate_health(canary, stable)
    if healthy:
        print("CANARY HEALTHY — ready to progress to next stage")
        sys.exit(0)
    else:
        print("CANARY UNHEALTHY — hold progression")
        for f in failures:
            print(f"  FAIL: {f}")
        sys.exit(1)

# canary_promote.py — advance canary from current stage to next
import subprocess, sys

STAGES = [1, 5, 10, 25, 50, 100]
FEATURE = "new_model_v2"

def get_current_percentage(feature: str) -> int:
    result = subprocess.run(
        ["kubectl", "get", "configmap", "ai-feature-flags",
         "-o", f"jsonpath={{.data.{feature}_percentage}}"],
        capture_output=True, text=True, check=True
    )
    return int(result.stdout.strip())

def set_percentage(feature: str, pct: int) -> None:
    patch = {"data": {f"{feature}_percentage": str(pct)}}
    import json
    subprocess.run(
        ["kubectl", "patch", "configmap", "ai-feature-flags",
         "--type", "merge", "-p", json.dumps(patch)],
        check=True
    )

def advance_stage(feature: str) -> None:
    current = get_current_percentage(feature)
    try:
        idx = STAGES.index(current)
    except ValueError:
        print(f"Current percentage {current} not in stage list {STAGES}")
        sys.exit(1)
    if idx + 1 >= len(STAGES):
        print(f"Already at final stage ({current}%), rollout complete")
        sys.exit(0)
    next_pct = STAGES[idx + 1]
    print(f"Advancing {feature}: {current}% -> {next_pct}%")
    set_percentage(feature, next_pct)
    print(f"Advanced. Monitor for hold period before next promotion.")

if __name__ == "__main__":
    advance_stage(FEATURE)
